import React, { useCallback, useEffect, useState } from 'react';
import classNames from 'classnames';

import './notification.scss';

import { NotificationT } from 'Shared/types/NotificationT';
import { notificationService } from 'Services/notificationService';
import { useDidMount } from 'Shared/hooks/useDidMount';
import useChanged from 'Shared/hooks/useChanged';

type PropsT = {
  notification: NotificationT;
};

const HIDE_ANIMATION_TIME = 500;

const Notification = ({ notification }: PropsT) => {
  const [show, setShow] = useState(false);

  const [timer, setTimer] = useState<NodeJS.Timeout | null>(null);

  const startTimer = useCallback(() => {
    const timer = setTimeout(() => {
      notificationService.removeAlert(notification.id);
    }, notification.showTime);

    setTimer(timer);

    return timer;
  }, [notification.id, notification.showTime]);

  const stopTimer = useCallback(() => {
    if (timer) {
      clearTimeout(timer);

      setTimer(null);
    }
  }, [timer]);

  const hideAtChanged = useChanged(notification.hideAt);

  useEffect(() => {
    if (hideAtChanged && notification.hideAt > 0) {
      setTimeout(() => {
        notificationService.clearAlert(notification.id);
      }, HIDE_ANIMATION_TIME);
    }
  }, [hideAtChanged, notification.hideAt, notification.id]);

  useDidMount(() => {
    requestAnimationFrame(() => {
      setShow(true);
    });

    const timer = startTimer();

    return () => {
      clearTimeout(timer);
    };
  });

  return (
    <div
      className={classNames('notification', {
        'notification--show': show,
        'notification--hide': notification.hideAt > 0,
      })}
      onMouseEnter={stopTimer}
      onMouseLeave={startTimer}
    >
      {notification.content}
    </div>
  );
};

export default Notification;

