import React from 'react';
import { createPortal } from 'react-dom';

import './notificationFeature.scss';

import { useGlobalValue } from 'Shared/store/useGlobalValue';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import Notification from './Notification';

const notificationContainer = document.getElementById('notification_portal');

const NotificationFeature = () => {
  const notifications = useGlobalValue(GlobalStoreFieldE.NOTIFICATIONS);

  return createPortal(
    <div className="notification-container">
      {notifications.map(notification => (
        <Notification
          key={notification.id}
          notification={notification}
        />
      ))}
    </div>,
    notificationContainer!,
  );
};

export default NotificationFeature;

