import { useCallback } from 'react';
import { useMutation } from '@tanstack/react-query';

import { requestClient } from 'Shared/requestClient/requestClient';
import { RequestRecordDataT } from 'Shared/types/api/RequestRecordDataT';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { queryClient } from 'Shared/requestClient/queryClient';
import { CreatedBankAccountDTO } from 'Repositories/bankAccounts/types/CreatedBankAccountDTO';

import { BankAccountDTO } from './types/BankAccountDTO';
import { CreateBankAccountSDTO } from './types/CreateBankAccountSDTO';

export const useCreateBankAccount = () => {
  const mutation = useMutation({
    mutationFn: async (data: CreateBankAccountSDTO) => {
      const response = await requestClient.post<
        RequestRecordDataT<CreatedBankAccountDTO>
      >(ApiGatewayE.BANK_ACCOUNTS, undefined, data);

      return response?.record;
    },
  });

  return useCallback(
    async (accountBody: CreateBankAccountSDTO) => {
      const newBankAccount = await mutation.mutateAsync(accountBody);

      if (newBankAccount) {
        queryClient.setQueryData<BankAccountDTO[]>(
          [ApiGatewayE.BANK_ACCOUNTS],
          oldData => {
            if (!oldData) return [newBankAccount];

            return [newBankAccount, ...oldData];
          },
        );
      }
    },
    [mutation],
  );
};

