import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';

import { requestClient } from 'Shared/requestClient/requestClient';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { useGlobalValue } from 'Shared/store/useGlobalValue';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { IdsListKeyE } from 'Shared/types/IdsListKeyE';
import { RequestRecordDataT } from 'Shared/types/api/RequestRecordDataT';

import { BankAccountDTO } from './types/BankAccountDTO';

export const useLoadBankAccount = (accountId?: string) => {
  const deletedBankAccountIds = useGlobalValue(GlobalStoreFieldE.IDS_LIST)[
    IdsListKeyE.DELETED_BANK_ACCOUNTS
  ];

  const preparedResult = useQuery({
    enabled: !!accountId,
    queryFn: async () => {
      if (!accountId) return undefined;

      const res = await requestClient.get<RequestRecordDataT<BankAccountDTO>>(
        ApiGatewayE.BANK_ACCOUNTS,
        accountId,
      );

      return res.record;
    },
    queryKey: [ApiGatewayE.BANK_ACCOUNTS, accountId],
  });

  const account: BankAccountDTO | undefined = useMemo(() => {
    const apiAcc = preparedResult.data;

    if (!apiAcc) return undefined;

    if (deletedBankAccountIds?.includes(apiAcc.id)) {
      return undefined;
    }

    return apiAcc;
  }, [preparedResult.data, deletedBankAccountIds]);

  return {
    loading: preparedResult.isLoading,
    account,
  };
};

