import { useCallback } from 'react';
import { useMutation } from '@tanstack/react-query';

import { UuidT } from 'Shared/types/UuidT';
import { requestClient } from 'Shared/requestClient/requestClient';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';
import { queryClient } from 'Shared/requestClient/queryClient';
import { useSaveRemoval } from 'Shared/hooks/saveRemovalNotification/useSaveRemoval';
import { IdsListKeyE } from 'Shared/types/IdsListKeyE';
import { BankAccountDTO } from 'Repositories/bankAccounts/types/BankAccountDTO';

export const useDeleteBankAccount = () => {
  const mutation = useMutation({
    mutationFn: async (accountId: UuidT) => {
      await requestClient.delete(ApiGatewayE.BANK_ACCOUNTS, [accountId]);
    },
  });

  return useSaveRemoval(
    IdsListKeyE.DELETED_BANK_ACCOUNTS,
    useCallback(
      async (accountIds: UuidT[]) => {
        await Promise.all(accountIds.map(id => mutation.mutateAsync(id)));

        queryClient.setQueryData<BankAccountDTO[]>(
          [ApiGatewayE.BANK_ACCOUNTS],
          oldData => {
            if (!oldData) {
              return oldData;
            }

            return oldData.filter(item => !accountIds.includes(item.id));
          },
        );
      },
      [mutation],
    ),
  );
};

