import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { globalStore, GlobalStoreT } from 'Shared/store/globalStore';

export const useGlobalValue = <T extends GlobalStoreFieldE>(
  globalStoreField: T,
): GlobalStoreT[T]['value'] => {
  return useSyncExternalStore(
    callback => {
      const unsubscribe = globalStore[globalStoreField].subscribe(callback);
      return () => unsubscribe();
    },
    () => globalStore[globalStoreField].value,
  );
};

