import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { globalStore, GlobalStoreT } from 'Shared/store/globalStore';

type CallBackT<T extends GlobalStoreFieldE> = (
  currentValue: GlobalStoreT[T]['value'],
) => GlobalStoreT[T]['value'];

export const createGlobalValueSetter = <T extends GlobalStoreFieldE>(
  globalStoreField: T,
) => {
  return (
    nextValue: GlobalStoreT[T]['value'] | CallBackT<T>,
  ): GlobalStoreT[T]['value'] => {
    if (typeof nextValue === 'function') {
      globalStore[globalStoreField].value = nextValue(
        globalStore[globalStoreField].value,
      );

      return globalStore[globalStoreField].value;
    }

    globalStore[globalStoreField].value = nextValue;

    return globalStore[globalStoreField].value;
  };
};

