import React from 'react';

import Sidebar from 'Components/sidebar/Sidebar';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import { useCreateBankAccount } from 'Repositories/bankAccounts/useCreateBankAccount';
import { AuFormOnSubmitT } from 'Components/form/AuFormOnSubmitT';
import { sidebarService } from 'Services/sidebarService';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import { replacePathValidationError } from 'Shared/utils/replacePathValidationError';
import { BankAccountSourceE } from 'Repositories/bankAccounts/types/BankAccountSourceE';

import BankAccountForm from '../form/BankAccountForm';
import { BankAccountFormFieldT } from '../form/BankAccountFormFieldT';
import { BankAccountFormFieldE } from '../form/BankAccountFormFieldE';

const CreateBankAccountSidebar = () => {
  const onCreateAccount = useCreateBankAccount();

  const onFormSubmit: AuFormOnSubmitT<BankAccountFormFieldT> = async data => {
    try {
      await onCreateAccount({
        availableBalance: 0,
        initialBalance: 0,
        limit: 0,
        currentBalance: parseInt(data[BankAccountFormFieldE.BALANCE], 10),
        institutionName: data[BankAccountFormFieldE.BANK_NAME],
        isoCurrencyCode: data[BankAccountFormFieldE.CURRENCY][0],
        name: data[BankAccountFormFieldE.ACCOUNT_NAME],
        openedAt: data[BankAccountFormFieldE.OPENED_AT]
          ? new Date(data[BankAccountFormFieldE.OPENED_AT]).toISOString()
          : '',
        source: BankAccountSourceE.MANUAL,
        type: data[BankAccountFormFieldE.ACCOUNT_TYPE][0],
      });

      sidebarService.close(SidebarNameE.CREATE_BANK_ACCOUNT);
    } catch (err) {
      replacePathValidationError(err, {
        currentBalance: BankAccountFormFieldE.BALANCE,
        institutionName: BankAccountFormFieldE.BANK_NAME,
        isoCurrencyCode: BankAccountFormFieldE.CURRENCY,
        name: BankAccountFormFieldE.ACCOUNT_NAME,
        openedAt: BankAccountFormFieldE.OPENED_AT,
        type: BankAccountFormFieldE.ACCOUNT_TYPE,
      });
    }
  };

  return (
    <Sidebar
      title="Add account"
      name={SidebarNameE.CREATE_BANK_ACCOUNT}
    >
      <BankAccountForm
        formId="createBankAccount"
        onSubmit={onFormSubmit}
      />

      <div className="account-form-buttons">
        <AuButton
          form="createBankAccount"
          kind={AuButtonKindE.SECONDARY}
          size={AuButtonSizeE.LARGE}
          type="submit"
        >
          Add account
        </AuButton>
      </div>
    </Sidebar>
  );
};

export default CreateBankAccountSidebar;

