export const errorReporter = {
  warn: (...args: unknown[]) => {
    console.warn(...args);
  },

  report: (error: unknown, ...args: unknown[]) => {
    if (error instanceof Error) {
      console.error(error, ...args);

      return;
    }

    console.error(new Error(error as string), ...args);
  },
};

